def main() -> None:
    """Parse source files and generate the flow diagram."""
    print("Reading source files...")

    text_normalizer_src = _read_module("text_normalizer.py")
    entity_extractor_src = _read_module("entity_extractor.py")
    normalizer_en_src = _read_module("normalizer_en.py")
    normalizer_ms_src = _read_module("normalizer_ms.py")

    print("Extracting entity types...")
    entity_types = extract_entity_types(entity_extractor_src)
    entity_pattern_methods = extract_entity_pattern_methods(entity_extractor_src)

    print("Extracting pipeline steps...")
    pipeline_steps = extract_pipeline_steps(text_normalizer_src)

    print("Extracting English normalizer steps...")
    en_steps = extract_normalizer_steps(normalizer_en_src, "text_normalize")

    print("Extracting Malay normalizer steps...")
    ms_steps = extract_normalizer_steps(normalizer_ms_src, "normalize_malay")

    print("Generating markdown...")
    content = generate_markdown(
        entity_types=entity_types,
        entity_pattern_methods=entity_pattern_methods,
        pipeline_steps=pipeline_steps,
        en_steps=en_steps,
        ms_steps=ms_steps,
    )

    output = HEADER + "\n" + content

    # Ensure output directory exists
    REPO_ANALYSIS.mkdir(parents=True, exist_ok=True)

    OUTPUT_FILE.write_text(output, encoding="utf-8")
    print(f"Generated {OUTPUT_FILE}")
    print(f"  Entity types found: {len(entity_types)}")
    print(f"  Pipeline steps: {len(pipeline_steps)}")
    print(f"  English normalizer steps: {len(en_steps)}")
    print(f"  Malay normalizer steps: {len(ms_steps)}")


if __name__ == "__main__":
    main()
